#!/usr/bin/env python3
"""
SAP Cloud Integration Analyzer Tool – Desktop UI
Built with CustomTkinter for cross-platform, no-server operation.

Usage:
    pip install customtkinter
    python ui.py
"""

import os
import sys
import platform
import subprocess
import threading
from pathlib import Path
import base64 as _b64

# ── Analysis-runner mode ───────────────────────────────────────────────────────
# When the frozen binary is called with --run-analysis it skips the GUI entirely
# and runs main.main() using the bundled Python environment (which has all
# required packages like python-dotenv, requests, etc.).  This avoids the
# ModuleNotFoundError that occurs when system Python is used instead.
if "--run-analysis" in sys.argv:
    sys.argv.remove("--run-analysis")
    if getattr(sys, "frozen", False):
        # Make bundled modules (main.py, src/) importable
        sys.path.insert(0, sys._MEIPASS)
    import main as _main_module
    sys.exit(_main_module.main())

from tkinter import filedialog, messagebox, PhotoImage

import customtkinter as ctk

# ─── Windows: declare a unique App User Model ID before any window is created ──
# This makes the Windows taskbar show the custom icon instead of python.exe's.
if platform.system() == "Windows":
    try:
        import ctypes
        ctypes.windll.shell32.SetCurrentProcessExplicitAppUserModelID(
            "SAP.CIAnalyzerTool.1"
        )
    except Exception:
        pass

# ─── Theme  ────────────────────────────────────────────────────────────────────
# Change these two lines to restyle the entire app.
ctk.set_appearance_mode("dark")      # "dark" | "light" | "system"
ctk.set_default_color_theme("blue")  # "blue" | "green" | "dark-blue"

