# ─── Main Application ──────────────────────────────────────────────────────────

class CIAnalyzerUI(ctk.CTk):
    """Main application window."""

    def __init__(self):
        super().__init__()
        self.title("SAP CI Analyzer Tool")
        self.geometry("760x680")
        self.minsize(680, 520)

        self.process: subprocess.Popen | None = None

        # Widget registry:
        #   key → {"var": tk-var, "widgets": [widget, ...], "label": CTkLabel, "field_def": dict}
        self._registry: dict[str, dict] = {}

        # Set taskbar / window icon
        try:
            if platform.system() == "Windows":
                # Write ICO to project dir (or use cached copy) and call iconbitmap()
                ico_path = _BASE_DIR / "icon.ico"
                if not ico_path.exists():
                    ico_path.write_bytes(_b64.b64decode(_APP_ICO_B64))
                self.iconbitmap(str(ico_path))
            else:
                _icon = PhotoImage(data=_APP_ICON_B64)
                self.iconphoto(True, _icon)
                self._icon_ref = _icon
        except Exception:
            pass  # icon is cosmetic — never block startup

        self._build_layout()
        self._load_env()

    # ── Layout builders ────────────────────────────────────────────────────────

    def _build_layout(self):
        self.tabview = ctk.CTkTabview(self, anchor="nw")
        self.tabview.pack(fill="both", expand=True, padx=12, pady=12)

        self.tabview.add("⚙  Configuration")
        self.tabview.add("▶  Run & Output")

        self._build_config_tab(self.tabview.tab("⚙  Configuration"))
        self._build_run_tab(self.tabview.tab("▶  Run & Output"))

    def _build_config_tab(self, parent: ctk.CTkFrame):
        # Scrollable area fills all available space
        scroll = ctk.CTkScrollableFrame(parent, label_text="")
        scroll.pack(fill="both", expand=True, padx=0, pady=(0, 6))
        scroll.grid_columnconfigure(1, weight=1)

        # Group fields by section (preserving declaration order)
        sections: dict[str, list[dict]] = {}
        for field in ENV_FIELDS:
            sections.setdefault(field["section"], []).append(field)

        grid_row = 0
        for section_name, fields in sections.items():
            # Section header row
            header = ctk.CTkLabel(
                scroll,
                text=f"  {section_name}",
                font=ctk.CTkFont(size=12, weight="bold"),
                fg_color=("gray75", "gray28"),
                corner_radius=5,
                anchor="w",
                height=28,
            )
            header.grid(
                row=grid_row, column=0, columnspan=3,
                sticky="ew", padx=6, pady=(14, 4)
            )
            grid_row += 1

            for field in fields:
                grid_row = self._add_field_row(scroll, field, grid_row)

        # Action buttons
        btn_bar = ctk.CTkFrame(parent, fg_color="transparent")
        btn_bar.pack(fill="x", padx=6, pady=(0, 4))

        ctk.CTkButton(
            btn_bar,
            text="💾  Save .env",
            command=self._save_env,
            width=140,
        ).pack(side="left", padx=(0, 10))

        ctk.CTkButton(
            btn_bar,
            text="▶  Run Analysis",
            command=self._run_analysis,
            width=150,
            fg_color=("#1a6fab", "#1f6aa5"),
            hover_color=("#155a8a", "#1a5a8a"),
        ).pack(side="left")

    def _add_field_row(
        self, parent: ctk.CTkScrollableFrame, field: dict, grid_row: int
    ) -> int:
        """Render one .env field into the grid. Returns the next available row."""
        key = field["key"]
        ftype = field["type"]
        label_text = field["label"]
        placeholder = field.get("placeholder", "")

        label = ctk.CTkLabel(parent, text=label_text, anchor="w", width=185)
        label.grid(row=grid_row, column=0, sticky="w", padx=(10, 4), pady=4)

        widgets: list = []  # all interactive widgets for this field

        if ftype in ("entry", "password"):
            var = ctk.StringVar()
            entry = ctk.CTkEntry(
                parent,
                textvariable=var,
                placeholder_text=placeholder,
                show="●" if ftype == "password" else "",
                width=340,
            )
            entry.grid(row=grid_row, column=1, sticky="ew", padx=4, pady=4)
            widgets.append(entry)

            if ftype == "password":
                eye = ctk.CTkButton(
                    parent,
                    text="👁",
                    width=36,
                    height=28,
                    fg_color="transparent",
                    hover_color=("gray80", "gray35"),
                    command=lambda e=entry: self._toggle_password(e),
                )
                eye.grid(row=grid_row, column=2, padx=(2, 8), pady=4)
                widgets.append(eye)

        elif ftype == "file_browse":
            var = ctk.StringVar()
            entry = ctk.CTkEntry(
                parent,
                textvariable=var,
                placeholder_text=placeholder,
                width=300,
            )
            entry.grid(row=grid_row, column=1, sticky="ew", padx=4, pady=4)
            widgets.append(entry)

            browse_btn = ctk.CTkButton(
                parent,
                text="📂 Browse",
                width=90,
                height=28,
                command=lambda v=var: self._browse_db_file(v),
            )
            browse_btn.grid(row=grid_row, column=2, padx=(2, 8), pady=4)
            widgets.append(browse_btn)

        elif ftype == "dropdown":
            options = field.get("options", [])
            var = ctk.StringVar(value=field.get("default", options[0] if options else ""))
            menu = ctk.CTkOptionMenu(
                parent,
                variable=var,
                values=options,
                width=180,
            )
            menu.grid(row=grid_row, column=1, sticky="w", padx=4, pady=4)
            widgets.append(menu)

        elif ftype == "checkbox":
            default_val = field.get("default", "false")
            var = ctk.BooleanVar(value=str(default_val).lower() in ("true", "1", "yes"))
            check = ctk.CTkCheckBox(parent, text="", variable=var)
            check.grid(row=grid_row, column=1, sticky="w", padx=4, pady=4)
            widgets.append(check)

        else:
            # Unknown type – skip but reserve row
            var = ctk.StringVar()

        self._registry[key] = {
            "var": var,
            "widgets": widgets,
            "label": label,
            "field_def": field,
        }

        return grid_row + 1

    def _build_run_tab(self, parent: ctk.CTkFrame):
        # Status bar
        status_bar = ctk.CTkFrame(parent, height=38, corner_radius=6)
        status_bar.pack(fill="x", padx=4, pady=(4, 6))
        status_bar.pack_propagate(False)

        self.status_label = ctk.CTkLabel(
            status_bar,
            text="● Ready",
            font=ctk.CTkFont(size=12),
            anchor="w",
        )
        self.status_label.pack(side="left", padx=14, pady=6)

        # Output textbox
        self.output_box = ctk.CTkTextbox(
            parent,
            font=ctk.CTkFont(family="Courier New", size=12),
            wrap="none",
            state="disabled",
        )
        self.output_box.pack(fill="both", expand=True, padx=4, pady=(0, 6))

        # Button bar
        btn_bar = ctk.CTkFrame(parent, fg_color="transparent")
        btn_bar.pack(fill="x", padx=4, pady=(0, 4))

        self.stop_btn = ctk.CTkButton(
            btn_bar,
            text="■  Stop",
            command=self._stop_process,
            width=110,
            state="disabled",
            fg_color=("#8b1a1a", "#8b1a1a"),
            hover_color=("#a52020", "#a52020"),
        )
        self.stop_btn.pack(side="left", padx=(0, 8))

        ctk.CTkButton(
            btn_bar,
            text="📂  Open Runs Folder",
            command=self._open_runs_folder,
            width=165,
        ).pack(side="left")

        ctk.CTkButton(
            btn_bar,
            text="🗑  Clear",
            command=self._clear_output,
            width=90,
            fg_color="transparent",
            hover_color=("gray80", "gray35"),
            border_width=1,
        ).pack(side="right")

    # ── Dependency wiring ──────────────────────────────────────────────────────

    def _connect_dependencies(self):
        """Attach trace callbacks to all driver fields and apply initial state."""
        for key, info in self._registry.items():
            field = info["field_def"]
            if "depends_on" in field:
                dep_key = next(iter(field["depends_on"]))
                if dep_key in self._registry:
                    self._registry[dep_key]["var"].trace_add(
                        "write",
                        lambda *_args, k=key: self._update_field_state(k),
                    )

        # Special rule: CF subaccount only supports OAUTH
        if "SAP_SUBACCOUNT_TYPE" in self._registry and "SAP_AUTH_TYPE" in self._registry:
            self._registry["SAP_SUBACCOUNT_TYPE"]["var"].trace_add(
                "write",
                lambda *_: self._enforce_cf_auth_rule(),
            )

        # Apply initial state for all fields
        for key in self._registry:
            self._update_field_state(key)
        self._enforce_cf_auth_rule()

    def _enforce_cf_auth_rule(self):
        """When CF subaccount is selected, lock Auth Type to OAUTH only."""
        subaccount_info = self._registry.get("SAP_SUBACCOUNT_TYPE")
        auth_info = self._registry.get("SAP_AUTH_TYPE")
        if not subaccount_info or not auth_info:
            return

        is_cf = subaccount_info["var"].get() == "CF"
        auth_menu: ctk.CTkOptionMenu = auth_info["widgets"][0]

        if is_cf:
            # Force OAUTH and remove BASIC from the dropdown
            auth_info["var"].set("OAUTH")
            auth_menu.configure(values=["OAUTH"])
        else:
            # NEO: restore both options
            auth_menu.configure(values=["OAUTH", "BASIC"])

        # Re-evaluate show/hide of auth-dependent fields after any auth type change
        for key in self._registry:
            self._update_field_state(key)

    def _update_field_state(self, key: str):
        """Show or hide a field row based on its depends_on condition."""
        info = self._registry.get(key)
        if not info:
            return
        field = info["field_def"]
        if "depends_on" not in field:
            return

        dep_key, dep_val = next(iter(field["depends_on"].items()))
        dep_info = self._registry.get(dep_key)
        if not dep_info:
            return

        visible = dep_info["var"].get() == dep_val

        if visible:
            info["label"].grid()          # restore with remembered grid options
            for widget in info["widgets"]:
                try:
                    widget.grid()         # restore
                except Exception:
                    pass
        else:
            info["label"].grid_remove()   # hide but remember grid position
            for widget in info["widgets"]:
                try:
                    widget.grid_remove()
                except Exception:
                    pass

    # ── .env I/O ───────────────────────────────────────────────────────────────

    def _load_env(self):
        """Read .env (or .env.example fallback) and populate form fields."""
        values: dict[str, str] = {}

        source = ENV_FILE if ENV_FILE.exists() else (ENV_EXAMPLE if ENV_EXAMPLE.exists() else None)
        if source:
            try:
                from dotenv import dotenv_values
                values = dotenv_values(str(source))
            except Exception as exc:
                messagebox.showwarning(
                    "Load Warning", f"Could not parse {source.name}:\n{exc}"
                )

        for key, info in self._registry.items():
            field = info["field_def"]
            raw = values.get(key, field.get("default", ""))
            var = info["var"]
            try:
                if field["type"] == "checkbox":
                    var.set(str(raw).lower() in ("true", "1", "yes"))
                else:
                    var.set(raw or "")
            except Exception:
                pass

        # Auto-check ENABLE_DISCOVER if any discover field is already set
        if "ENABLE_DISCOVER" in self._registry:
            has_discover = bool(values.get("DISCOVER_BASE_URL", "").strip())
            self._registry["ENABLE_DISCOVER"]["var"].set(has_discover)

        # Wire up dynamic field enable/disable after values are set
        self._connect_dependencies()

    def _save_env(self) -> bool:
        """Write form values back to .env, preserving comments from the original."""
        # Collect current form values (skip UI-only fields marked save=False)
        new_values: dict[str, str] = {}
        for key, info in self._registry.items():
            if not info["field_def"].get("save", True):
                continue                        # UI-only field — do not persist
            var = info["var"]
            if info["field_def"]["type"] == "checkbox":
                new_values[key] = "true" if var.get() else "false"
            else:
                new_values[key] = var.get()

        # Read existing file (or template) to preserve comments and order
        template_source = (
            ENV_FILE if ENV_FILE.exists()
            else (ENV_EXAMPLE if ENV_EXAMPLE.exists() else None)
        )

        output_lines: list[str] = []
        written: set[str] = set()

        if template_source:
            with open(template_source, "r", encoding="utf-8") as fh:
                for line in fh:
                    stripped = line.strip()
                    if stripped.startswith("#") or stripped == "":
                        output_lines.append(line)
                    elif "=" in stripped:
                        k = stripped.split("=", 1)[0].strip()
                        if k in new_values:
                            output_lines.append(f"{k}={new_values[k]}\n")
                            written.add(k)
                        else:
                            output_lines.append(line)
                    else:
                        output_lines.append(line)

        # Append keys not present in the template
        for k, v in new_values.items():
            if k not in written:
                output_lines.append(f"{k}={v}\n")

        try:
            with open(ENV_FILE, "w", encoding="utf-8") as fh:
                fh.writelines(output_lines)
            return True
        except OSError as exc:
            messagebox.showerror("Save Error", f"Could not write .env:\n{exc}")
            return False

    # ── Run / Stop ─────────────────────────────────────────────────────────────

    def _run_analysis(self):
        """Save .env then launch main.py as a subprocess."""
        if self.process and self.process.poll() is None:
            messagebox.showinfo(
                "Already Running", "Analysis is already in progress.\nStop it first."
            )
            return

        if not self._save_env():
            return

        self._clear_output()
        self.tabview.set("▶  Run & Output")
        self._set_status("● Running…", color="#FFA040")
        self.stop_btn.configure(state="normal")

        if getattr(sys, "frozen", False):
            # Re-invoke the frozen binary with --run-analysis so it uses the
            # bundled Python environment (all packages already included).
            cmd = [sys.executable, "--run-analysis"]
            cwd = str(_BASE_DIR)
        else:
            cmd = [sys.executable, str(MAIN_SCRIPT)]
            cwd = str(MAIN_SCRIPT.parent)

        try:
            self.process = subprocess.Popen(
                cmd,
                stdout=subprocess.PIPE,
                stderr=subprocess.STDOUT,
                text=True,
                bufsize=1,
                encoding="utf-8",
                errors="replace",
                cwd=cwd,
            )
            threading.Thread(target=self._stream_output, daemon=True).start()
        except Exception as exc:
            self._append_output(f"[ERROR] Failed to start process:\n{exc}\n")
            self._set_status("● Error", color="#FF4444")
            self.stop_btn.configure(state="disabled")

    def _stream_output(self):
        """Background thread: read subprocess output line-by-line."""
        try:
            for line in self.process.stdout:
                self._append_output(line)
            self.process.wait()
            rc = self.process.returncode

            if rc == 0:
                self._append_output("\n✅  Analysis completed successfully!\n")
                self.after(0, lambda: self._set_status("● Completed", color="#44CC44"))
            elif rc == 130:  # KeyboardInterrupt / SIGINT
                self._append_output("\n⚠️  Stopped by user.\n")
                self.after(0, lambda: self._set_status("● Stopped", color="#888888"))
            else:
                self._append_output(f"\n❌  Process exited with code {rc}\n")
                self.after(0, lambda: self._set_status(f"● Failed (exit {rc})", color="#FF4444"))

        except Exception as exc:
            self._append_output(f"\n[ERROR] Output stream error: {exc}\n")
        finally:
            self.after(0, lambda: self.stop_btn.configure(state="disabled"))

    def _stop_process(self):
        """Send SIGTERM to the running subprocess."""
        if self.process and self.process.poll() is None:
            self.process.terminate()
            self._set_status("● Stopping…", color="#AAAAAA")

    # ── Helper methods ─────────────────────────────────────────────────────────

    def _append_output(self, text: str):
        """Thread-safe: append text to the output box."""
        def _do():
            self.output_box.configure(state="normal")
            self.output_box.insert("end", text)
            self.output_box.see("end")
            self.output_box.configure(state="disabled")

        self.after(0, _do)

    def _clear_output(self):
        self.output_box.configure(state="normal")
        self.output_box.delete("1.0", "end")
        self.output_box.configure(state="disabled")
        self._set_status("● Ready")

    def _set_status(self, text: str, color: str = ("gray10", "gray90")):
        self.status_label.configure(text=text, text_color=color)

    @staticmethod
    def _toggle_password(entry: ctk.CTkEntry):
        entry.configure(show="" if entry.cget("show") else "●")

    @staticmethod
    def _browse_db_file(string_var: ctk.StringVar):
        runs_dir = Path("runs")
        initial = str(runs_dir.resolve()) if runs_dir.exists() else "."
        path = filedialog.askopenfilename(
            title="Select SQLite Database",
            initialdir=initial,
            filetypes=[("SQLite Database", "*.db"), ("All Files", "*.*")],
        )
        if path:
            string_var.set(path)

    @staticmethod
    def _open_runs_folder():
        runs_dir = Path("runs").resolve()
        if not runs_dir.exists():
            runs_dir = Path(".").resolve()

        system = platform.system()
        try:
            if system == "Windows":
                os.startfile(str(runs_dir))
            elif system == "Darwin":
                subprocess.Popen(["open", str(runs_dir)])
            else:
                subprocess.Popen(["xdg-open", str(runs_dir)])
        except Exception as exc:
            messagebox.showerror("Open Folder", f"Could not open folder:\n{exc}")


# ─── Entry point ───────────────────────────────────────────────────────────────

def main():
    # Verify customtkinter is available before doing anything else
    try:
        import customtkinter  # noqa: F401
    except ImportError:
        print(
            "[ERROR] customtkinter is not installed.\n"
            "Run:  pip install customtkinter\n"
            "Then re-launch:  python ui.py"
        )
        sys.exit(1)

    app = CIAnalyzerUI()
    app.mainloop()


if __name__ == "__main__":
    main()